# ── Custom Lambda Authoriser ──────────────────────────────────────────
# Placed in front of ALL routes — runs before the backend Lambda
def authoriser_handler(event, context):
    """
    event = {
      'type': 'TOKEN',
      'authorizationToken': 'Bearer eyJhbGci...',
      'methodArn': 'arn:aws:execute-api:us-east-1:123:abc123/prod/GET/users'
    }
    Must return an IAM policy document.
    Result is cached for 300s by default (TTL configurable).
    """
    token = event['authorizationToken'].replace('Bearer ', '')

    try:
        # Validate token (your custom logic — JWT, API key DB lookup, etc.)
        user_id = validate_token(token)  # raises if invalid

        # Return ALLOW policy — Lambda proxy receives the event
        return {
            'principalId': user_id,
            'policyDocument': {
                'Version': '2012-10-17',
                'Statement': [{
                    'Action': 'execute-api:Invoke',
                    'Effect': 'Allow',
                    'Resource': event['methodArn']
                }]
            },
            'context': {
                # Passed to backend Lambda as event['requestContext']['authorizer']
                'userId': user_id,
                'plan': 'premium'
            }
        }
    except Exception:
        # Returning DENY or raising 'Unauthorized' both result in 401
        raise Exception('Unauthorized')

def validate_token(token):
    # In practice: verify JWT signature + expiry
    # Or: check API key against DynamoDB table
    if token == 'valid-token-123':
        return 'user-42'
    raise ValueError('Invalid token')

# ── Backend Lambda — accesses authoriser context ───────────────────────
def api_handler(event, context):
    # Authoriser's context dict is available here
    authoriser_context = event['requestContext']['authorizer']['lambda']
    user_id = authoriser_context.get('userId')
    plan = authoriser_context.get('plan')  # 'premium' or 'free'

    # Apply plan-based logic
    if plan == 'free' and expensive_operation_requested(event):
        return {
            'statusCode': 402,
            'body': json.dumps({'error': 'Upgrade to premium for this feature'})
        }

    return {
        'statusCode': 200,
        'body': json.dumps({'userId': user_id, 'data': fetch_data(user_id)})
    }

def expensive_operation_requested(event):
    return event.get('queryStringParameters', {}).get('export') == 'true'

