# ── DynamoDB Streams — Lambda triggered on table changes ───────────────
# Stream records land in Lambda's event['Records']
def stream_handler(event, context):
    """
    DynamoDB Streams delivers change events to Lambda.
    Each record has:
      eventName: INSERT | MODIFY | REMOVE
      dynamodb.NewImage: item after change (INSERT/MODIFY)
      dynamodb.OldImage: item before change (MODIFY/REMOVE)
    """
    for record in event['Records']:
        event_name = record['eventName']
        new_image = record['dynamodb'].get('NewImage', {})
        old_image = record['dynamodb'].get('OldImage', {})

        # Deserialise DynamoDB typed format → Python dict
        def deserialise(item):
            from boto3.dynamodb.types import TypeDeserializer
            d = TypeDeserializer()
            return {k: d.deserialize(v) for k, v in item.items()}

        if event_name == 'MODIFY':
            new = deserialise(new_image)
            old = deserialise(old_image)

            # React to status change: PENDING → CONFIRMED
            if old.get('status') == 'PENDING' and new.get('status') == 'CONFIRMED':
                send_confirmation_email(new['userId'], new['orderId'])
                update_inventory(new['items'])
                print(f"Order {new['orderId']} confirmed for user {new['userId']}")

        elif event_name == 'INSERT':
            new = deserialise(new_image)
            if new.get('SK', '').startswith('ORDER#'):
                notify_warehouse(new)

        elif event_name == 'REMOVE':
            # TTL expiry: archive to S3 before deletion
            removed = deserialise(old_image)
            if removed.get('ttl'):  # TTL-triggered removal
                archive_to_s3(removed)

