def archive_to_s3(item):
    s3 = boto3.client('s3')
    s3.put_object(
        Bucket='order-archive',
        Key=f"orders/{item['userId']}/{item['orderId']}.json",
        Body=json.dumps(item, default=str)
    )

# ── Transactions — atomic multi-item operations ────────────────────────
def transfer_credits(from_user, to_user, amount):
    """
    Atomically debit from_user and credit to_user.
    Both succeed or both fail — no partial updates.
    Transactions: up to 100 items, up to 4MB, 2× WCU cost.
    """
    try:
        client.transact_write_items(
            TransactItems=[
                {
                    'Update': {
                        'TableName': 'UserAccounts',
                        'Key': {'PK': {'S': f'USER#{from_user}'}},
                        'UpdateExpression': 'SET credits = credits - :amount',
                        'ConditionExpression': 'credits >= :amount',  # Prevent negative balance
                        'ExpressionAttributeValues': {
                            ':amount': {'N': str(amount)}
                        }
                    }
                },
                {
                    'Update': {
                        'TableName': 'UserAccounts',
                        'Key': {'PK': {'S': f'USER#{to_user}'}},
                        'UpdateExpression': 'SET credits = credits + :amount',
                        'ExpressionAttributeValues': {
                            ':amount': {'N': str(amount)}
                        }
                    }
                }
            ]
        )
        print(f"Transferred {amount} credits from {from_user} to {to_user}")
    except client.exceptions.TransactionCanceledException as e:
        reasons = e.response['CancellationReasons']
        raise ValueError(f'Transfer failed: insufficient credits. Reasons: {reasons}')
